questions.question:
What does the following code output?

function check(x: string | number) {
  if (typeof x === 'string') {
    return x.toUpperCase();
  }
  return x.toFixed(2);
}
console.log(check(3.14159));

What does the following code output?

class Dog { bark() { return 'woof'; } }
class Cat { meow() { return 'meow'; } }

function speak(pet: Dog | Cat) {
  if (pet instanceof Dog) {
    return pet.bark();
  }
  return pet.meow();
}
console.log(speak(new Cat()));

What does the following code output?

type Fish = { swim: () => string };
type Bird = { fly: () => string };

function move(animal: Fish | Bird) {
  if ('swim' in animal) {
    return animal.swim();
  }
  return animal.fly();
}
console.log(move({ fly: () => 'soaring' }));

Given:

type Shape =
  | { kind: 'circle'; radius: number }
  | { kind: 'square'; side: number };

function area(s: Shape) {
  switch (s.kind) {
    case 'circle': return Math.PI * s.radius ** 2;
    case 'square': return s.side ** 2;
  }
}
console.log(area({ kind: 'square', side: 4 }));

What does this custom type guard do?

function isString(val: unknown): val is string {
  return typeof val === 'string';
}

What does the following code output?

function describe(x: string | null) {
  if (x !== null) {
    return x.length;
  }
  return -1;
}
console.log(describe(null));

What does the following output?

function process(val: string | number | boolean) {
  if (typeof val === 'string') {
    return 'S';
  } else if (typeof val === 'number') {
    return 'N';
  } else {
    return 'B';
  }
}
console.log(process(true));

What does this code output?

type Result = { ok: true; value: number } | { ok: false; error: string };

function show(r: Result) {
  if (r.ok) {
    return r.value * 2;
  }
  return r.error;
}
console.log(show({ ok: true, value: 21 }));

